import{_ as r,c as t,o as _,a as b}from"./app.015fbf38.js";const m='{"title":"\u4F46\u4EE5\u7406\u66F8\u7B2C\u516D\u7AE0","description":"","frontmatter":{"title":"\u4F46\u4EE5\u7406\u66F8\u7B2C\u516D\u7AE0","date":"2018-07-15T23:27:18.000Z","categories":["\u8B80\u7D93\u7D00\u9304"]},"headers":[],"relativePath":"Bike/BikeTravel/20180715_\u4F46\u4EE5\u7406\u66F8\u7B2C\u516D\u7AE0.md","lastUpdated":1648513476165}',e={},a=b('<p><img src="https://farm2.staticflickr.com/1766/41639043410_554cc988c0.jpg" alt=""><br></p><p>\u65B0\u7684\u4E00\u500B\u738B\u671D\u958B\u59CB\uFF0C\u5F9E\u5DF4\u6BD4\u502B\u5E1D\u570B\u8F49\u70BA\u6CE2\u65AF\u746A\u4EE3\u738B\u671D<br> \u5728\u6230\u4E8B\u983B\u7E41\uFF0C\u570B\u5BB6\u52D5\u76EA\u7684\u74B0\u5883\uFF0C\u738B\u96A8\u5FC3\u6240\u9858\u7ACB120\u500B\u7E3D\u7763<br> \u800C\u9019\u5176\u4E2D\uFF0C\u53C8\u5206\u5225\u7ACB\u4E86\u4E09\u540D\u7E3D\u9577\uFF0C\u4F46\u4EE5\u7406\u70BA3\u4EBA\u7E3D\u9577\u4E4B\u4E00<br> \u53EF\u4EE5\u770B\u51FA\u5373\u4F7F\u63DB\u4E86\u8001\u95C6\uFF0C\u4F46\u4EE5\u7406\u7684\u5DE5\u4F5C\u80FD\u529B\u4ECD\u53D7\u91CD\u7528<br> \u6216\u8A31\u662F\u524D\u671D\u8001\u81E3\uFF0C\u52A0\u4E0A\u662F\u5916\u90A6\u4EBA\uFF0C\u53C8\u906D\u4EBA\u773C\u7D05\u5FCC\u5992<br> \u4F46\u4EE5\u7406\u6709\u7F8E\u597D\u7684\u9748\u6027\uFF0C\u5177\u6709\u5353\u8D8A\u7684\u8FA6\u4E8B\u80FD\u529B\u6BEB\u7121\u904E\u5931<br> \u9019\u4E9B\u5FCC\u5992\u7684\u4EBA\uFF0C\u5C07\u6B6A\u8166\u7B4B\u52D5\u5230\u4FE1\u4EF0\u4E0A\uFF0C\u5F9E\u795E\u7684\u5F8B\u6CD5\u4E2D\u627E\u5C0B</p><p>\u5728\u534A\u8A98\u5C0E\uFF0C\u534A\u5439\u6367\u738B\u7684\u6B0A\u5A01\u4E0B\uFF0C\u8B93\u738B\u7C3D\u7F72\u4E0B\u4E86\u7981\u4EE4<br> \u4E09\u5341\u65E5\u5411\u738B\u4EE5\u5916\u7684\u795E\u6216\u4EBA\u7948\u6C42\uFF0C\u5C31\u5FC5\u6254\u5728\u7345\u5B50\u5751\u4E2D<br> \u53EF\u80FD\u9019\u662F\u6CE2\u65AF\u738B\u570B\u7684\u5F8B\u6CD5\uFF0C\u738B\u4E0B\u7684\u7981\u4EE4\u7121\u6CD5\u66F4\u6539<br> (\u7D93\u6587\u4E2D\u9023\u7E8C\u63D0\u4E86\u591A\u6B21\uFF0C\u53C3\u8003 V12,V15,V17)<br> \u4F46\u4EE5\u7406\u77E5\u9053\u5F8C\uFF0C\u4ECD\u9032\u884C\u5E73\u65E5\u4ED6\u7D20\u5E38\u64CD\u7DF4\u7684\u5C6C\u9748\u7FD2\u6163<br> \u4E00\u65E5\u4E09\u6B21\u3001\u96D9\u819D\u8DEA\u5728\u4ED6\u795E\u9762\u524D\u3001\u79B1\u544A\u611F\u8B1D(V10)</p><p>\u7576\u738B\u77E5\u9053\u5F8C\u4E5F\u70BA\u4F46\u4EE5\u7406\u7684\u8655\u5883\u64D4\u6182\uFF0C\u53EF\u80FD\u738B\u60DC\u624D<br> \u751A\u81F3\u7761\u4E0D\u597D\u5403\u4E0D\u4E0B\uFF0C\u5FC3\u88E1\u4E5F\u7C4C\u756B\u8981\u89E3\u6551\u4ED6<br> \u53EF\u4EE5\u6CE2\u65AF\u7684\u5F8B\u6CD5\uFF0C\u738B\u4E0D\u80FD\u9055\u53CD\u81EA\u5DF1\u6240\u4E0B\u7684\u7981\u4EE4<br> \u6B21\u65E5\u738B\u76F4\u5954\u7345\u5B50\u5751\uFF0C\u60F3\u770B\u4F46\u4EE5\u7406\u7684\u60C5\u6CC1\u5982\u4F55<br> \u53CD\u4E4B\uFF0C\u9677\u5BB3\u4F46\u4EE5\u7406\u7684\u4EBA\u96A8\u5373\u88AB\u6254\u5165\u7345\u5B50\u5751\u4E2D<br> \u751A\u81F3\u9084\u672A\u5230\u5751\u88E1\uFF0C\u5C31\u88AB\u7345\u5B50\u54AC\u6B7B</p><p>\u6700\u5F8C\u738B\u4E5F\u4E0B\u4EE4\uFF0C\u5BA3\u7A31\u4F46\u4EE5\u7406\u7684\u795E\u662F\u6C38\u9060\u9577\u5B58\u7684\u6D3B\u795E<br> \u4ED6\u7684\u570B\u6C38\u4E0D\u6557\u58DE\u3001\u4ED6\u7684\u6B0A\u67C4\u6C38\u5B58\u7121\u6975\uFF0E\u4ED6\u8B77\u5E87\u3001\u642D\u6551\u4EBA</p><p>\u7279\u5225\u7684\u9EDE\uFF1A</p><ol><li>\u4F46\u4EE5\u7406\u77E5\u9053\u4E86\u4ECD\u4E00\u65E5\u4E09\u6B21\u5411\u795E\u79B1\u544A<br> \u9019\u908A\u6709\u7279\u5225\u6307\u51FA\uFF0C\u4F46\u4EE5\u7406\u662F\u77E5\u9053\u7981\u4EE4\u5F8C\u53BB\u79B1\u544A\u7684<br> \u9019\u662F\u5F88\u96E3\u53BB\u505A\u5230\u7684\uFF0C\u5176\u5BE6\u4F46\u4EE5\u7406\u53EF\u4EE5\u79C1\u4E0B\u5BC6\u5BA4\u79B1\u544A<br> \u53EF\u4EE5\u514D\u65BC\u9019\u5834\u885D\u7A81\uFF0C\u4F46\u5C0D\u795E\u7684\u795E\u4FE1\u5FC3\u76F8\u5C0D\u4F3C\u4E4E\u8F03\u5C0F<br> \u9019\u7A2E\u60C5\u6CC1\u5E95\u4E0B\uFF0C\u4E00\u822C\u4EBA\u90FD\u6703\u9078\u64C7\u907F\u8AF1(\u5305\u542B\u6211\u4E5F\u662F)<br><br></li><li>\u4E0B\u6700\u5F8C\u6240\u4E0B\u7684\u53EC\u4EE4\uFF0C\u611F\u89BA\u5F88\u50CF\u662F\u5728\u4FDD\u8B77\u4F46\u4EE5\u7406<br> \u53EF\u80FD\u738B\u5E0C\u671B\u5927\u5BB6\u4E0D\u8981\u518D\u5F9E\u4F46\u4EE5\u7406\u7684\u4FE1\u4EF0\u9677\u5BB3\u4ED6<br> \u738B\u4E5F\u77E5\u9053\u6709\u4EBA\u89AC\u89A6\u4F46\u4EE5\u7406\u7684\u8077\u4F4D\uFF0C\u4F46\u53C8\u6C92\u8F12<br> \u64D4\u5FC3\u4E4B\u5F8C\u53EF\u80FD\u4E0D\u77E5\u6703\u5728\u88AB\u7528\u751A\u9EBC\u6280\u5006\u8AA3\u9677\u4F46\u4EE5\u7406<br> \u738B\u76F4\u63A5\u9812\u5E03\u4E0B\u4EE4\uFF0C\u800C\u4E14\u7981\u4EE4\u4E0B\u4E86\u5C31\u4E0D\u80FD\u518D\u66F4\u6539</li><li>\u5F9E\u982D\u5230\u5C3E\u4F46\u4EE5\u7406\u90FD\u6C92\u6709\u64D4\u5FC3\uFF0C\u6050\u61FC<br> \u4F46\u4EE5\u7406\u6240\u906D\u9047\u7684\u4E8B\u4EF6\uFF0C\u5B8C\u5168\u6C92\u770B\u5230\u64D4\u5FC3\u7684\u60C5\u7DD2<br> \u9762\u5C0D\u8077\u5834\u4E0A\u4E92\u76F8\u9677\u5BB3\u5F80\u4E0A\u722C\u7684\u60C5\u6CC1\uFF0C\u4E4B\u524D\u898B\u8B58\u904E\u4E86<br> \u4F46\u4EE5\u7406\u5C0D\u81EA\u5DF1\u7684\u5DE5\u4F5C\u5F88\u6709\u4FDD\u63E1\uFF0C\u7121\u6CD5\u88AB\u9677\u5BB3<br> (\u9019\u6642\u4F46\u4EE5\u7406\u5927\u7D04\u4E03\u5341\u5E7E\u5FEB\u516B\u5341\u6B72\uFF0C\u662F\u5927\u5E2B\u7D1A\u4EBA\u7269)<br> \u7576\u8981\u88AB\u4E1F\u7345\u5B50\u5751\u6642\uFF0C\u8207\u738B\u7684\u61C9\u7B54\u4E5F\u770B\u4E0D\u51FA\u64D4\u6182<br> \u6574\u7AE0\u89BA\u5F97\u4F46\u4EE5\u7406\u4ECD\u7DAD\u6301\u8457\u7A69\u5065\u3001\u5B89\u5B9A\u7684\u60C5\u7DD2<br> \u6216\u8A31\u662F\u9019\u6A23\u7684\u500B\u4EBA\u7279\u8CEA\uFF0C\u53CA\u512A\u7570\u7684\u5DE5\u4F5C\u80FD\u529B<br> \u4F46\u4EE5\u7406\u7279\u5225\u7372\u5F97\u5404\u500B\u4E0D\u540C\u671D\u4EE3\u7684\u738B\u6240\u8CDE\u8B58</li></ol>',7),c=[a];function i(o,p,s,l,n,d){return _(),t("div",null,c)}var T=r(e,[["render",i]]);export{m as __pageData,T as default};
